/// <reference lib="webworker" />
/**
 * SGP4 satellite propagation Worker — Phase 9 Leap Step 3.
 *
 * Receives the 15,457-satellite catalog and a category bitmask; ticks at
 * 1.5 Hz; posts back Float32Array of [lng, lat, altKm, ...] for the active
 * subset. Comlink-wrapped for typed RPC.
 *
 * Algorithm: satellite.js@^5 twoline2satrec + sgp4 propagation. The math is
 * NORAD's SGP4 with SDP4 selection for deep-space objects. Each tick does
 * ~25 ms of work for 15k sats on the RTX 4060 baseline.
 */
import * as Comlink from 'comlink';
import { twoline2satrec, propagate, gstime, eciToGeodetic } from 'satellite.js';

export interface SatInput {
  /** NORAD ID. */
  n: number;
  /** Category code 0..9. */
  c: number;
  /** TLE line 1. */
  l1: string;
  /** TLE line 2. */
  l2: string;
  /** Display name. */
  nm: string;
}

export interface SatPropagatedOut {
  /** Float32Array packed as [lng, lat, altKm, catCode, lng, lat, altKm, catCode, ...]. */
  positions: ArrayBuffer;
  /** Active satellite count (positions.byteLength = count * 16). */
  count: number;
  /** NORAD IDs in the same order as positions (for click resolution). */
  noradIds: Int32Array;
}

interface InternalState {
  records: Array<{ rec: ReturnType<typeof twoline2satrec>; cat: number; noradId: number }>;
  catBitmask: number;
}

let state: InternalState | null = null;

const api = {
  init(sats: ReadonlyArray<SatInput>, catBitmask = 0xff): void {
    const records: InternalState['records'] = [];
    for (const s of sats) {
      try {
        const rec = twoline2satrec(s.l1, s.l2);
        // Discard sats whose TLE doesn't parse (satrec.error != 0).
        if (rec.error) continue;
        records.push({ rec, cat: s.c, noradId: s.n });
      } catch {
        // Skip malformed entries.
      }
    }
    state = { records, catBitmask };
  },

  setCategoryBitmask(bitmask: number): void {
    if (state) state.catBitmask = bitmask;
  },

  /**
   * Propagate every enabled satellite to the given UTC epoch. Returns a
   * transferable buffer of positions in WGS-84 lat/lon/altKm.
   */
  propagate(epochMs: number): SatPropagatedOut {
    if (!state) return { positions: new ArrayBuffer(0), count: 0, noradIds: new Int32Array(0) };
    const date = new Date(epochMs);
    const gmst = gstime(date);
    const out: number[] = [];
    const ids: number[] = [];
    for (const { rec, cat, noradId } of state.records) {
      if ((state.catBitmask & (1 << cat)) === 0) continue;
      const pv = propagate(rec, date);
      // satellite.js returns either {x,y,z} or false depending on sgp4 status.
      if (!pv.position || typeof pv.position !== 'object') continue;
      const geo = eciToGeodetic(pv.position as { x: number; y: number; z: number }, gmst);
      const lng = (geo.longitude * 180) / Math.PI;
      const lat = (geo.latitude * 180) / Math.PI;
      const altKm = geo.height;
      if (!Number.isFinite(lng) || !Number.isFinite(lat)) continue;
      out.push(lng, lat, altKm, cat);
      ids.push(noradId);
    }
    const arr = new Float32Array(out);
    const idArr = new Int32Array(ids);
    return { positions: arr.buffer, count: ids.length, noradIds: idArr };
  },

  /** Get count of satellites per category in the currently-loaded set. */
  countsByCategory(): Record<number, number> {
    const counts: Record<number, number> = {};
    for (let i = 0; i < 10; i++) counts[i] = 0;
    if (!state) return counts;
    for (const { cat } of state.records) counts[cat] = (counts[cat] ?? 0) + 1;
    return counts;
  },
};

export type SatAPI = typeof api;

if (typeof self !== 'undefined' && typeof (self as DedicatedWorkerGlobalScope).postMessage === 'function') {
  Comlink.expose(api);
}
